const express = require('express');
const financeController = require('../controllers/financeController');
const multer = require('multer');
const path = require('path');
const fs = require('fs');

const router = express.Router();

// Ensure uploads directory exists
const uploadDir = path.join(__dirname, '../../uploads');
if (!fs.existsSync(uploadDir)) {
  fs.mkdirSync(uploadDir, { recursive: true });
}

// Configure multer for CSV file uploads
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, uploadDir);
  },
  filename: (req, file, cb) => {
    // Use timestamp + original name to avoid collisions
    const uniqueSuffix = `${Date.now()}-${Math.round(Math.random() * 1e9)}`;
    cb(null, `${uniqueSuffix}-${file.originalname}`);
  },
});

// File filter: only allow CSV files
const fileFilter = (req, file, cb) => {
  const allowedMimeTypes = ['text/csv', 'application/vnd.ms-excel', 'text/plain'];
  const ext = path.extname(file.originalname).toLowerCase();

  if (allowedMimeTypes.includes(file.mimetype) || ext === '.csv') {
    cb(null, true);
  } else {
    cb(new Error('Only CSV files are allowed'), false);
  }
};

const upload = multer({
  storage,
  fileFilter,
  limits: {
    fileSize: 10 * 1024 * 1024, // 10 MB limit
  },
});

// POST /api/finance/upload-csv
router.post('/upload-csv', upload.single('file'), financeController.uploadCsv);

// Handle multer errors at the route level
router.use((err, req, res, next) => {
  if (err instanceof multer.MulterError) {
    if (err.code === 'LIMIT_FILE_SIZE') {
      return res.status(400).json({ error: 'File size exceeds the 10 MB limit.' });
    }
    return res.status(400).json({ error: `File upload error: ${err.message}` });
  }
  if (err && err.message === 'Only CSV files are allowed') {
    return res.status(400).json({ error: err.message });
  }
  next(err);
});

module.exports = router;

const csvParser = require('../services/csvParser');
const Transaction = require('../models/Transaction');
const fs = require('fs');

/**
 * POST /api/finance/upload-csv
 * Accepts a multipart/form-data request with a CSV file field named "file".
 * Parses the CSV, stores transactions in SQLite, and returns the results.
 */
exports.uploadCsv = async (req, res) => {
  // Ensure a file was actually attached
  if (!req.file) {
    return res.status(400).json({ error: 'No file uploaded. Please attach a CSV file with field name "file".' });
  }

  const filePath = req.file.path;

  try {
    // Parse the uploaded CSV file into transaction objects
    const transactions = await csvParser.parseCsv(req.file);

    if (transactions.length === 0) {
      // Clean up the temp file before returning
      cleanupFile(filePath);
      return res.status(200).json({
        message: 'CSV file processed successfully, but no transactions were found.',
        transactions: [],
      });
    }

    // Persist all parsed transactions to the database
    const saved = await Transaction.bulkCreate(transactions);

    // Clean up the uploaded temp file after successful processing
    cleanupFile(filePath);

    return res.status(200).json({
      message: 'CSV file processed successfully',
      count: saved.length,
      transactions: saved,
    });
  } catch (error) {
    // Always attempt to clean up the temp file on error
    cleanupFile(filePath);

    // Distinguish between parsing errors and DB errors for clearer messages
    const statusCode = error.name === 'CsvParseError' ? 422 : 400;
    return res.status(statusCode).json({ error: error.message });
  }
};

/**
 * Safely removes a file from disk, ignoring errors if the file no longer exists.
 * @param {string} filePath - Absolute path to the file to remove.
 */
function cleanupFile(filePath) {
  if (!filePath) return;
  fs.unlink(filePath, (err) => {
    if (err && err.code !== 'ENOENT') {
      console.error(`[financeController] Failed to clean up temp file ${filePath}:`, err.message);
    }
  });
}

const csv = require('csv-parser');
const fs = require('fs');
const path = require('path');

/**
 * Custom error class for CSV parsing failures.
 * Allows the controller to distinguish parse errors from other errors.
 */
class CsvParseError extends Error {
  constructor(message) {
    super(message);
    this.name = 'CsvParseError';
  }
}

/**
 * Required columns that must be present in the CSV file (case-insensitive match).
 */
const REQUIRED_COLUMNS = ['date', 'description', 'amount'];

/**
 * Normalises a header string: trims whitespace and converts to lowercase.
 * @param {string} header
 * @returns {string}
 */
function normaliseHeader(header) {
  return header.trim().toLowerCase();
}

/**
 * Validates that all required columns are present in the parsed header set.
 * @param {Set<string>} headerSet - Set of normalised header names.
 * @throws {CsvParseError} if any required column is missing.
 */
function validateHeaders(headerSet) {
  const missing = REQUIRED_COLUMNS.filter((col) => !headerSet.has(col));
  if (missing.length > 0) {
    throw new CsvParseError(
      `CSV is missing required column(s): ${missing.join(', ')}. ` +
        `Expected columns: Date, Description, Amount (and optionally Category).`
    );
  }
}

/**
 * Parses a single CSV row into a transaction object.
 * Returns null if the row should be skipped (e.g. all fields empty).
 *
 * @param {Object} row - Raw row object from csv-parser (keys are original headers).
 * @param {Map<string, string>} headerMap - Maps normalised header -> original header.
 * @param {number} rowIndex - 1-based row index for error messages.
 * @returns {{ date: string, description: string, amount: number, category: string|null } | null}
 */
function parseRow(row, headerMap, rowIndex) {
  // Build a normalised key lookup so we can access columns case-insensitively
  const get = (normKey) => {
    const originalKey = headerMap.get(normKey);
    return originalKey !== undefined ? (row[originalKey] || '').trim() : '';
  };

  const dateRaw = get('date');
  const descriptionRaw = get('description');
  const amountRaw = get('amount');
  const categoryRaw = get('category');

  // Skip completely empty rows
  if (!dateRaw && !descriptionRaw && !amountRaw) {
    return null;
  }

  // Validate date
  if (!dateRaw) {
    throw new CsvParseError(`Row ${rowIndex}: "Date" field is empty.`);
  }

  // Validate description
  if (!descriptionRaw) {
    throw new CsvParseError(`Row ${rowIndex}: "Description" field is empty.`);
  }

  // Validate and parse amount
  if (!amountRaw) {
    throw new CsvParseError(`Row ${rowIndex}: "Amount" field is empty.`);
  }

  // Strip currency symbols and thousands separators before parsing
  const cleanedAmount = amountRaw.replace(/[^0-9.\-]/g, '');
  const amount = parseFloat(cleanedAmount);

  if (isNaN(amount)) {
    throw new CsvParseError(
      `Row ${rowIndex}: "Amount" value "${amountRaw}" is not a valid number.`
    );
  }

  return {
    date: dateRaw,
    description: descriptionRaw,
    amount,
    category: categoryRaw || null,
  };
}

/**
 * Parses an uploaded CSV file and returns an array of transaction objects.
 *
 * @param {Express.Multer.File} file - The multer file object (must have a `path` property).
 * @returns {Promise<Array<{ date: string, description: string, amount: number, category: string|null }>>}
 * @throws {CsvParseError} for invalid CSV structure or data.
 * @throws {Error} for file system errors.
 */
exports.parseCsv = (file) => {
  return new Promise((resolve, reject) => {
    if (!file || !file.path) {
      return reject(new CsvParseError('No file path provided for CSV parsing.'));
    }

    // Verify the file exists before attempting to stream it
    if (!fs.existsSync(file.path)) {
      return reject(new CsvParseError(`File not found at path: ${file.path}`));
    }

    const transactions = [];
    let rowIndex = 0;
    // headerMap: normalised header name -> original header name
    let headerMap = null;
    let headersValidated = false;

    const stream = fs.createReadStream(file.path)
      .pipe(
        csv({
          // Use mapHeaders to capture the original headers while normalising for lookup
          mapHeaders: ({ header }) => header, // keep originals; we normalise manually
          skipEmptyLines: true,
        })
      );

    stream
      .on('headers', (headers) => {
        // Build a map of normalised -> original header names
        headerMap = new Map();
        for (const h of headers) {
          headerMap.set(normaliseHeader(h), h);
        }

        // Validate required columns are present
        try {
          validateHeaders(new Set(headerMap.keys()));
          headersValidated = true;
        } catch (err) {
          stream.destroy(err);
        }
      })
      .on('data', (row) => {
        if (!headersValidated) return; // headers failed validation; stream is being destroyed
        rowIndex++;
        try {
          const transaction = parseRow(row, headerMap, rowIndex);
          if (transaction !== null) {
            transactions.push(transaction);
          }
        } catch (err) {
          // Stop processing on the first bad row
          stream.destroy(err);
        }
      })
      .on('end', () => {
        resolve(transactions);
      })
      .on('error', (error) => {
        // Wrap non-CsvParseError errors so the controller can identify them
        if (error instanceof CsvParseError) {
          reject(error);
        } else {
          reject(new CsvParseError(`Failed to read CSV file: ${error.message}`));
        }
      });
  });
};

// Export the error class so tests and controllers can use it
exports.CsvParseError = CsvParseError;

const db = require('../../config/db');

/**
 * Transaction model.
 * Provides methods to interact with the `transactions` table in SQLite.
 *
 * Schema:
 *   id          INTEGER PRIMARY KEY AUTOINCREMENT
 *   date        TEXT    NOT NULL   -- ISO date string or original date text from CSV
 *   description TEXT    NOT NULL
 *   amount      REAL    NOT NULL   -- Positive = credit, Negative = debit
 *   category    TEXT               -- Optional category label
 *   created_at  TEXT    NOT NULL   -- ISO timestamp of insertion
 */

/**
 * Ensures the `transactions` table exists in the database.
 * Called once at module load time.
 */
function initTable() {
  const sql = `
    CREATE TABLE IF NOT EXISTS transactions (
      id          INTEGER PRIMARY KEY AUTOINCREMENT,
      date        TEXT    NOT NULL,
      description TEXT    NOT NULL,
      amount      REAL    NOT NULL,
      category    TEXT,
      created_at  TEXT    NOT NULL DEFAULT (datetime('now'))
    )
  `;
  // db.run is synchronous in better-sqlite3; use db.exec for DDL
  try {
    db.exec(sql);
  } catch (err) {
    console.error('[Transaction] Failed to initialise transactions table:', err.message);
    throw err;
  }
}

// Initialise the table when the module is first required
initTable();

/**
 * Inserts a single transaction record.
 *
 * @param {{ date: string, description: string, amount: number, category?: string|null }} transaction
 * @returns {{ id: number, date: string, description: string, amount: number, category: string|null, created_at: string }}
 */
function create(transaction) {
  const { date, description, amount, category = null } = transaction;

  if (!date || typeof date !== 'string') {
    throw new Error('Transaction.create: "date" must be a non-empty string.');
  }
  if (!description || typeof description !== 'string') {
    throw new Error('Transaction.create: "description" must be a non-empty string.');
  }
  if (typeof amount !== 'number' || isNaN(amount)) {
    throw new Error('Transaction.create: "amount" must be a valid number.');
  }

  const stmt = db.prepare(`
    INSERT INTO transactions (date, description, amount, category)
    VALUES (@date, @description, @amount, @category)
  `);

  const info = stmt.run({ date, description, amount, category });

  return findById(info.lastInsertRowid);
}

/**
 * Inserts multiple transaction records in a single database transaction.
 * If any insertion fails the entire batch is rolled back.
 *
 * @param {Array<{ date: string, description: string, amount: number, category?: string|null }>} transactions
 * @returns {Array<{ id: number, date: string, description: string, amount: number, category: string|null, created_at: string }>}
 */
function bulkCreate(transactions) {
  if (!Array.isArray(transactions)) {
    throw new Error('Transaction.bulkCreate: argument must be an array.');
  }
  if (transactions.length === 0) {
    return [];
  }

  const stmt = db.prepare(`
    INSERT INTO transactions (date, description, amount, category)
    VALUES (@date, @description, @amount, @category)
  `);

  // Wrap all inserts in a single SQLite transaction for atomicity and performance
  const insertMany = db.transaction((rows) => {
    const inserted = [];
    for (const row of rows) {
      const { date, description, amount, category = null } = row;

      if (!date || typeof date !== 'string') {
        throw new Error(`Transaction.bulkCreate: "date" must be a non-empty string (got: ${JSON.stringify(date)}).`);
      }
      if (!description || typeof description !== 'string') {
        throw new Error(`Transaction.bulkCreate: "description" must be a non-empty string (got: ${JSON.stringify(description)}).`);
      }
      if (typeof amount !== 'number' || isNaN(amount)) {
        throw new Error(`Transaction.bulkCreate: "amount" must be a valid number (got: ${JSON.stringify(amount)}).`);
      }

      const info = stmt.run({ date, description, amount, category });
      inserted.push(info.lastInsertRowid);
    }
    return inserted;
  });

  const ids = insertMany(transactions);

  // Fetch and return the fully persisted records
  return ids.map((id) => findById(id));
}

/**
 * Retrieves a single transaction by its primary key.
 *
 * @param {number} id
 * @returns {{ id: number, date: string, description: string, amount: number, category: string|null, created_at: string } | undefined}
 */
function findById(id) {
  return db.prepare('SELECT * FROM transactions WHERE id = ?').get(id);
}

/**
 * Retrieves all transactions, ordered by date descending.
 *
 * @returns {Array<{ id: number, date: string, description: string, amount: number, category: string|null, created_at: string }>}
 */
function findAll() {
  return db.prepare('SELECT * FROM transactions ORDER BY date DESC').all();
}

/**
 * Deletes all transactions from the table.
 * Useful for testing and seeding.
 *
 * @returns {number} Number of rows deleted.
 */
function deleteAll() {
  const info = db.prepare('DELETE FROM transactions').run();
  return info.changes;
}

module.exports = {
  create,
  bulkCreate,
  findById,
  findAll,
  deleteAll,
};

const Database = require('better-sqlite3');
const path = require('path');
const fs = require('fs');

// Allow the database path to be overridden via environment variable.
// Defaults to a file named `financial_assistant.db` in the project root.
const DB_PATH =
  process.env.DATABASE_PATH ||
  path.join(__dirname, '..', 'financial_assistant.db');

// Ensure the directory for the database file exists
const dbDir = path.dirname(DB_PATH);
if (!fs.existsSync(dbDir)) {
  fs.mkdirSync(dbDir, { recursive: true });
}

/**
 * Singleton better-sqlite3 database instance.
 * better-sqlite3 is synchronous and safe to share across the application.
 */
let db;

try {
  db = new Database(DB_PATH, {
    // Log SQL statements in development for easier debugging
    verbose: process.env.NODE_ENV === 'development' ? console.log : null,
  });

  // Enable WAL mode for better concurrent read performance
  db.pragma('journal_mode = WAL');
  // Enforce foreign key constraints
  db.pragma('foreign_keys = ON');

  console.log(`[db] Connected to SQLite database at: ${DB_PATH}`);
} catch (err) {
  console.error('[db] Failed to open SQLite database:', err.message);
  process.exit(1);
}

module.exports = db;

const express = require('express');
const path = require('path');
const financeRoutes = require('./routes/financeRoutes');

const app = express();

// ── Body parsers ──────────────────────────────────────────────────────────────
