  const status = err.status || err.statusCode || 500;
  res.status(status).json({
    error: err.message || 'Internal server error',
  });
});

module.exports = app;

/**
 * Unit tests for the CSV parsing service.
 * Uses Jest and temporary files to simulate real uploads.
 */

const fs = require('fs');
const path = require('path');
const os = require('os');
const { parseCsv, CsvParseError } = require('../../server/services/csvParser');

/**
 * Helper: writes content to a temp file and returns a multer-like file object.
 * @param {string} content
 * @param {string} [filename]
 * @returns {{ path: string, originalname: string }}
 */
function createTempFile(content, filename = 'test.csv') {
  const tmpPath = path.join(os.tmpdir(), `${Date.now()}-${filename}`);
  fs.writeFileSync(tmpPath, content, 'utf8');
  return { path: tmpPath, originalname: filename };
}

/**
 * Helper: removes a temp file if it exists.
 */
function removeTempFile(filePath) {
  if (filePath && fs.existsSync(filePath)) {
    fs.unlinkSync(filePath);
  }
}

describe('csvParser.parseCsv', () => {
  // ── Happy path ──────────────────────────────────────────────────────────────

  test('parses a well-formed CSV with all columns', async () => {
    const content = [
      'Date,Description,Amount,Category',
      '2024-01-15,Coffee Shop,-4.50,Food',
      '2024-01-16,Salary,3000.00,Income',
    ].join('\n');

    const file = createTempFile(content);
    try {
      const transactions = await parseCsv(file);
      expect(transactions).toHaveLength(2);
      expect(transactions[0]).toEqual({
        date: '2024-01-15',
        description: 'Coffee Shop',
        amount: -4.5,
        category: 'Food',
      });
      expect(transactions[1]).toEqual({
        date: '2024-01-16',
        description: 'Salary',
        amount: 3000.0,
        category: 'Income',
      });
    } finally {
      removeTempFile(file.path);
    }
  });

  test('parses a CSV without the optional Category column', async () => {
    const content = [
      'Date,Description,Amount',
      '2024-02-01,Rent,-1200.00',
    ].join('\n');

    const file = createTempFile(content);
    try {
      const transactions = await parseCsv(file);
      expect(transactions).toHaveLength(1);
      expect(transactions[0].category).toBeNull();
    } finally {
      removeTempFile(file.path);
    }
  });

  test('handles headers with mixed case', async () => {
    const content = [
      'DATE,DESCRIPTION,AMOUNT,CATEGORY',
      '2024-03-10,Gym,-50.00,Health',
    ].join('\n');

    const file = createTempFile(content);
    try {
      const transactions = await parseCsv(file);
      expect(transactions).toHaveLength(1);
      expect(transactions[0].amount).toBe(-50);
    } finally {
      removeTempFile(file.path);
    }
  });

  test('strips currency symbols from amount', async () => {
    const content = [
      'Date,Description,Amount',
      '2024-04-01,Groceries,$-75.30',
    ].join('\n');

    const file = createTempFile(content);
    try {
      const transactions = await parseCsv(file);
      expect(transactions[0].amount).toBe(-75.3);
    } finally {
      removeTempFile(file.path);
    }
  });

  test('skips completely empty rows', async () => {
    const content = [
      'Date,Description,Amount,Category',
      '2024-05-01,Taxi,-12.00,Transport',
      ',,, ',
      '2024-05-02,Bus,-2.50,Transport',
    ].join('\n');

    const file = createTempFile(content);
    try {
      const transactions = await parseCsv(file);
      expect(transactions).toHaveLength(2);
    } finally {
      removeTempFile(file.path);
    }
  });

  test('returns empty array for a CSV with only headers', async () => {
    const content = 'Date,Description,Amount,Category\n';
    const file = createTempFile(content);
    try {
      const transactions = await parseCsv(file);
      expect(transactions).toHaveLength(0);
    } finally {
      removeTempFile(file.path);
    }
  });

  // ── Error cases ─────────────────────────────────────────────────────────────

  test('throws CsvParseError when required columns are missing', async () => {
    const content = [
      'Date,Notes',
      '2024-06-01,Something',
    ].join('\n');

    const file = createTempFile(content);
    try {
      await expect(parseCsv(file)).rejects.toThrow(CsvParseError);
      await expect(parseCsv(file)).rejects.toThrow(/missing required column/);
    } finally {
      removeTempFile(file.path);
    }
  });

  test('throws CsvParseError when Amount is not a number', async () => {
    const content = [
      'Date,Description,Amount',
      '2024-07-01,Bad Row,not-a-number',
    ].join('\n');

    const file = createTempFile(content);
    try {
      await expect(parseCsv(file)).rejects.toThrow(CsvParseError);
      await expect(parseCsv(file)).rejects.toThrow(/not a valid number/);
    } finally {
      removeTempFile(file.path);
    }
  });

  test('throws CsvParseError when Date field is empty', async () => {
    const content = [
      'Date,Description,Amount',
      ',Missing Date,-10.00',
    ].join('\n');

    const file = createTempFile(content);
    try {
      await expect(parseCsv(file)).rejects.toThrow(CsvParseError);
      await expect(parseCsv(file)).rejects.toThrow(/"Date" field is empty/);
    } finally {
      removeTempFile(file.path);
    }
  });

  test('throws CsvParseError when file does not exist', async () => {
    const fakeFile = { path: '/tmp/nonexistent-file-xyz.csv', originalname: 'fake.csv' };
    await expect(parseCsv(fakeFile)).rejects.toThrow(CsvParseError);
    await expect(parseCsv(fakeFile)).rejects.toThrow(/File not found/);
  });

  test('throws CsvParseError when no file object is provided', async () => {
    await expect(parseCsv(null)).rejects.toThrow(CsvParseError);
  });
});

/**
 * Integration tests for the finance controller / upload-csv endpoint.
 * Uses Supertest to simulate HTTP requests and an in-memory SQLite database.
 */

const request = require('supertest');
const path = require('path');
const fs = require('fs');
const os = require('os');

// ── Set up an in-memory database BEFORE requiring any app modules ──────────────
process.env.DATABASE_PATH = ':memory:';

const app = require('../../server/app');
const Transaction = require('../../server/models/Transaction');

/**
 * Helper: writes a CSV string to a temp file and returns its path.
 */
function writeTempCsv(content, filename = 'upload.csv') {
  const tmpPath = path.join(os.tmpdir(), `${Date.now()}-${filename}`);
  fs.writeFileSync(tmpPath, content, 'utf8');
  return tmpPath;
}

beforeEach(() => {
  // Clear the transactions table before each test for isolation
  Transaction.deleteAll();
});

describe('POST /api/finance/upload-csv', () => {
  // ── Happy path ──────────────────────────────────────────────────────────────

  test('returns 200 and parsed transactions for a valid CSV', async () => {
    const csvContent = [
      'Date,Description,Amount,Category',
      '2024-01-10,Supermarket,-55.20,Groceries',
      '2024-01-11,Freelance Invoice,1500.00,Income',
    ].join('\n');

    const tmpPath = writeTempCsv(csvContent);

    const res = await request(app)
      .post('/api/finance/upload-csv')
      .attach('file', tmpPath, 'transactions.csv');

    fs.unlinkSync(tmpPath);

    expect(res.status).toBe(200);
    expect(res.body.message).toMatch(/successfully/);
    expect(res.body.count).toBe(2);
    expect(res.body.transactions).toHaveLength(2);
    expect(res.body.transactions[0]).toMatchObject({
      date: '2024-01-10',
      description: 'Supermarket',
      amount: -55.2,
      category: 'Groceries',
    });
  });

  test('stores transactions in the database', async () => {
    const csvContent = [
      'Date,Description,Amount',
      '2024-02-01,Rent,-1200.00',
    ].join('\n');

    const tmpPath = writeTempCsv(csvContent);

    await request(app)
      .post('/api/finance/upload-csv')
      .attach('file', tmpPath, 'rent.csv');

    fs.unlinkSync(tmpPath);

    const all = Transaction.findAll();
    expect(all).toHaveLength(1);
    expect(all[0].description).toBe('Rent');
    expect(all[0].amount).toBe(-1200);
  });

  test('returns 200 with empty transactions array for header-only CSV', async () => {
    const csvContent = 'Date,Description,Amount,Category\n';
    const tmpPath = writeTempCsv(csvContent);

    const res = await request(app)
      .post('/api/finance/upload-csv')
      .attach('file', tmpPath, 'empty.csv');

    fs.unlinkSync(tmpPath);

    expect(res.status).toBe(200);
    expect(res.body.transactions).toHaveLength(0);
  });

  // ── Error cases ─────────────────────────────────────────────────────────────

  test('returns 400 when no file is attached', async () => {
    const res = await request(app)
      .post('/api/finance/upload-csv');

    expect(res.status).toBe(400);
    expect(res.body.error).toMatch(/No file uploaded/);
  });

  test('returns 400 when a non-CSV file is uploaded', async () => {
    // Create a fake text file with a .txt extension
    const tmpPath = path.join(os.tmpdir(), `${Date.now()}-test.txt`);
    fs.writeFileSync(tmpPath, 'This is not a CSV file.', 'utf8');

    const res = await request(app)
      .post('/api/finance/upload-csv')
      .attach('file', tmpPath, 'notacsv.txt');

    fs.unlinkSync(tmpPath);

    expect(res.status).toBe(400);
    expect(res.body.error).toMatch(/Only CSV files are allowed/);
  });

  test('returns 422 when CSV is missing required columns', async () => {
    const csvContent = [
      'Date,Notes',
      '2024-03-01,Something',
    ].join('\n');

    const tmpPath = writeTempCsv(csvContent);

    const res = await request(app)
      .post('/api/finance/upload-csv')
      .attach('file', tmpPath, 'bad_columns.csv');

    fs.unlinkSync(tmpPath);

    expect(res.status).toBe(422);
    expect(res.body.error).toMatch(/missing required column/);
  });

  test('returns 422 when CSV contains an invalid amount', async () => {
    const csvContent = [
      'Date,Description,Amount',
      '2024-04-01,Bad Row,not-a-number',
    ].join('\n');

    const tmpPath = writeTempCsv(csvContent);

    const res = await request(app)
      .post('/api/finance/upload-csv')
      .attach('file', tmpPath, 'bad_amount.csv');

    fs.unlinkSync(tmpPath);

    expect(res.status).toBe(422);
    expect(res.body.error).toMatch(/not a valid number/);
  });
});

